    import java.util.HashMap;
    import java.util.Map;
    import sailpoint.object.Link;
    import sailpoint.object.Identity;
    import sailpoint.object.Filter;
    import sailpoint.object.QueryOptions;
    import org.apache.log4j.Logger;
    import org.apache.log4j.Level;
    import sailpoint.tools.Util;

    //Logger logger = Logger.getLogger("rule.Correlation.Ascension-AD-Correlation-Rule");
    
    public boolean onlyNumbers(String string){
        return string.matches("^[0-9]*$");
    }
 
    public String findIdentityByMatchSecondary(String lastName,String dateOfBirth, String last4SSN){
        //logger.debug("Searching for identity by 3 attributes.");
        //logger.debug("lastName is:  "+ lastName);
        //logger.debug("dateOfBirth is:  "+ dateOfBirth);
        //logger.debug("last4SSN is:  "+ last4SSN);
        
        QueryOptions op2 = new QueryOptions();
        Filter[] filters2 = new Filter[1];
        List filterList2 = new ArrayList();
        filterList2.add(Filter.eq("lastname", lastName));
        filterList2.add(Filter.eq("dob", dateOfBirth));
        filterList2.add(Filter.eq("ssn", last4SSN));
        filters2[0] = Filter.and(filterList2);
        op2.add(filters2);
        Iterator identityItr = context.search(Identity.class, op2, "name");
        String correlatedIdentityName = "";
        int count = 0;
        while( identityItr.hasNext()) {
            Object[] eachObject = identityItr.next();
            correlatedIdentityName = eachObject[0];
            count++;
        }
        if(count ==1 && Util.isNotNullOrEmpty(correlatedIdentityName)){
            return correlatedIdentityName;          
        }
        return null;
    }

    Map returnMap = new HashMap();
    boolean found = false;
    String employeeNumber = (String) account.getAttribute("employeeNumber");
    String consistencyGuid = (String) account.getAttribute("mS-DS-ConsistencyGuid");
    String objectGuid = (String) account.getAttribute("objectguid");
    String userID = (String) account.getAttribute("sAMAccountName");
    
    //logger.debug("employeeNumber :"+ employeeNumber);
    //logger.debug("userID :"+ userID);
    //logger.debug("consistencyGuid :"+ consistencyGuid);
    //logger.debug("objectGuid :"+ objectGuid);

    if(Util.isNotNullOrEmpty(employeeNumber)){
        if(onlyNumbers(employeeNumber) && !"0".equals(employeeNumber) && !"99999".equals(employeeNumber)){
            QueryOptions qo = new QueryOptions();
            Filter f = Filter.eq("employeeId", employeeNumber);
            Filter caseFilter = Filter.ignoreCase(f);
            qo.addFilter(caseFilter);
            Iterator it = context.search(Identity.class, qo, "name");
            while(it.hasNext()){
              String identityName = (String)it.next()[0];
              //logger.debug("1.Found Existing Link :"+ identityName);
              found = true;
              returnMap.put("identityName", identityName);
              break;
            }
            if (null != it) {
              Util.flushIterator(it);
            }
        }
    }

    if (!found){
        if(Util.isNotNullOrEmpty(userID)){
            QueryOptions qo = new QueryOptions();
            Filter f = Filter.or(Filter.eq("samAccountName", userID),Filter.eq("name", userID));
            Filter caseFilter = Filter.ignoreCase(f);
            qo.addFilter(caseFilter);
            Iterator it = context.search(Identity.class, qo, "name");
            while(it.hasNext()){
              String identityName = (String)it.next()[0];
              //logger.debug("1.Found Existing Link :"+ identityName);
              found = true;
              returnMap.put("identityName", identityName);
              break;
            }
            if (null != it) {
              Util.flushIterator(it);
            }
        }
      
                    if(Util.isNotNullOrEmpty(userID) && userID.contains("-adm")){
			  int admLoc =  userID.lastIndexOf("-adm");
			  String mainUserID = userID.substring(0,admLoc);
			  
            QueryOptions qo = new QueryOptions();
            Filter f = Filter.or(Filter.eq("samAccountName", mainUserID),Filter.eq("name", mainUserID));
            Filter caseFilter = Filter.ignoreCase(f);
            qo.addFilter(caseFilter);
            Iterator it = context.search(Identity.class, qo, "name");
            while(it.hasNext()){
              String identityName = (String)it.next()[0];
              //logger.debug("1.Found Existing Link :"+ identityName);
              found = true;
              returnMap.put("identityName", identityName);
              break;
            }
            if (null != it) {
              Util.flushIterator(it);
            }
        }

        if(!found){
            if(Util.isNotNullOrEmpty(consistencyGuid)){
                Filter f = null;
                QueryOptions qo = new QueryOptions();
                f = Filter.eq("consistencyGuid", consistencyGuid);
                qo.addFilter(f);
                Iterator it = context.search(Link.class, qo, "identity.name");
                while(it.hasNext()){
                  String identityName = (String)it.next()[0];
                  //logger.debug("1.Found Existing Link :"+ identityName);
                  found = true;
                  returnMap.put("identityName", identityName);
                  break;
                }
                if (null != it) {
                  Util.flushIterator(it);
                }
            }
            if(!found) {
                if(Util.isNotNullOrEmpty(objectGuid)){ 
                  Filter filter = null;
                  QueryOptions qopt = new QueryOptions();    
                  filter = Filter.eq("objectGuid", objectGuid);
                  qopt.addFilter(filter);
                  Iterator itr = context.search(Link.class, qopt, "identity.name");
                  while(itr.hasNext()){
                    String identityName = (String)itr.next()[0];
                    //logger.debug("2.Found Existing Link :"+ identityName);
                    found = true;
                    
                    returnMap.put("identityName", identityName);
                    break;
                  }
                  if(!found){
                     String _lastname = account.getStringAttribute("sn");
                     String _dateOfBirth = account.getStringAttribute("employeeType");
                     String _last4SSN = account.getStringAttribute("departmentNumber");
                     if(Util.isNotNullOrEmpty(_lastname) && Util.isNotNullOrEmpty(_dateOfBirth) && Util.isNotNullOrEmpty(_last4SSN)){
                         String foundUser = findIdentityByMatchSecondary(_lastname,_dateOfBirth, _last4SSN);
                         if(foundUser != null){
                             returnMap.put("identityName", foundUser);
                             found = true;
                         }
                     }
                  }
                  if (null != itr) {
                    Util.flushIterator(itr);
                  }
                }
            }
        }
    }
    
	// check child
  if(!Util.isEmpty(returnMap)  && Util.isNotNullOrEmpty(returnMap.get("identityName") )){

    String tempName = getPrimaryIdentityNameByName(returnMap.get("identityName"));
    if(Util.isNotNullOrEmpty(tempName)){
      returnMap.put("identityName", tempName);
    }
  }
  
    return returnMap;
